import { NavLink, useNavigate } from "react-router-dom";
import { clearToken } from "../utils/auth";

const linkBaseClass = "px-3 py-2 rounded-md text-sm font-medium";

const Navbar = () => {
  const navigate = useNavigate();

  const handleLogout = () => {
    clearToken();
    navigate("/login", { replace: true });
  };

  return (
    <nav className="bg-slate-900 text-white px-4 py-3">
      <div className="max-w-6xl mx-auto flex items-center justify-between">
        <h1 className="text-lg font-semibold">Library Management</h1>
        <div className="flex gap-2 items-center">
          <NavLink
            to="/dashboard"
            className={({ isActive }) =>
              `${linkBaseClass} ${isActive ? "bg-slate-700" : "hover:bg-slate-800"}`
            }
          >
            Dashboard
          </NavLink>
          <NavLink
            to="/books"
            className={({ isActive }) =>
              `${linkBaseClass} ${isActive ? "bg-slate-700" : "hover:bg-slate-800"}`
            }
          >
            Books
          </NavLink>
          <NavLink
            to="/users"
            className={({ isActive }) =>
              `${linkBaseClass} ${isActive ? "bg-slate-700" : "hover:bg-slate-800"}`
            }
          >
            Users
          </NavLink>
          <NavLink
            to="/issue-return"
            className={({ isActive }) =>
              `${linkBaseClass} ${isActive ? "bg-slate-700" : "hover:bg-slate-800"}`
            }
          >
            Issue/Return
          </NavLink>
          <button
            type="button"
            className="px-3 py-2 rounded-md text-sm font-medium bg-red-700 hover:bg-red-600"
            onClick={handleLogout}
          >
            Logout
          </button>
        </div>
      </div>
    </nav>
  );
};

export default Navbar;
